    m = re.search(r'\(2016\)', header)
    if m:
        return 2016
    # fallback: first year in header
    m = re.search(r'\b(20\d{2}|19\d{2})\b', header)
    if m:
        return int(m.group(0))
    # last resort: search entire text
    m = re.search(r'\b(20\d{2}|19\d{2})\b', text)
    if m:
        return int(m.group(0))
